INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (236, 'EFFECT_NE', '14051', '对于设备而言我们以前主要是用flash来存储文件，后来增加了硬盘，只有在硬盘不工作的情况下才用flash，所以如果设备有硬盘的话，这类告警通常没有，因为读写的都为硬盘介质，但如果只有flash的设备的话，那么影响是比较大的，因为flash上放置的是版本和配置，如果是硬件坏了，那么整个设备都不起作用了，如果是更新软件的话，那回退版本还是没有问题的。', 111, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
