INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (250, 'EFFECT_NE', '14076', '新注册用户由于CPU过载被阻塞\n·部分已注册成功低优先级的白名单用户，被阻塞，无法发起呼叫\n·CPU冲高，系统存在超负荷工作的风险，影响部分已注册用户的正常呼叫', 125, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (251, 'EFFECT_NE', '14077', '1、进入循环处理，有自恢复情况，如果是业务任务或者协议栈进入循环处理，可能导致业务的延迟或者断续\n如果时间超过1分钟，会导致系统复位。\n2、如果是信令媒体合一设备，复位期间所有新发起业务请求都会失败，所有当前正在进行的业务会中断。\n3、如果是单纯信令面设备复位，已经开始的数据不会中断，新发起业务失败。\n4、如果是媒体设备复位，当前所有数据业务会中断，新注册业务正常，新呼叫等数据业务会失败。\n5、如果系统做了备份冗余，设备复位会导致业务转移到备份设备进行，业务不受影响。', 126, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (252, 'EFFECT_NE', '14078', '配置的DNS服务器不能为SBC服务，系统配置中使用到该DNS域名的业务，都会受到影响；如果配置的存在备用DNS服务器，且该DNS没有创建socket失败告警，对系统的影响相对会小些', 127, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (253, 'EFFECT_NE', '14079', '试用License超期后边界网关上配置的试用License所承载的注册、呼叫将会中断，超期之前业务不会受到影响', 128, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
