INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (266, 'EFFECT_NE', '14092', '如果边界网关所承载的并发呼叫数量进一步上升，超过系统License配置中针对最大并发在线呼叫许可容量部分的会话建立请求将被拒绝，产生呼损降低系统接通率。随着并发呼叫数量的下降，将恢复正常。', 141, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
