INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (270, 'EFFECT_NE', '14096', 'ZXUN B200不能及时将ACR发给CCF，当ACR不断被写入文件，文件占用的硬盘空间达到配置的最大可用空间后，之后产生的ACR被丢弃，从而无法进行离线计费，导致商业损失。', 145, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
