INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (416, 'EFFECT_SERVICE', '14047', 'CPU负荷过高可能会引起设备运行异常，如果配置了CPU话控功能，业务量很大时可能会导致呼叫失败，注册失败等业务质量下降。', 112, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
