INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (418, 'EFFECT_SERVICE', '14049', '边界网关上配置的试用License所承载的注册、呼叫将会中断', 114, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (419, 'EFFECT_SERVICE', '14050', '对于设备而言我们以前主要是用flash来存储文件，后来增加了硬盘，只有在硬盘不工作的情况下才用flash，所以如果设备有硬盘的话，这类告警通常没有，因为读写的都为硬盘介质，但如果只有flash的设备的话，那么影响是比较大的，因为flash上放置的是版本和配置，如果是硬件坏了，那么整个设备都不起作用了，如果是更新软件的话，那回退版本还是没有问题的。', 115, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (420, 'EFFECT_SERVICE', '14051', '无法进行离线计费，导致商业损失', 116, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (421, 'EFFECT_SERVICE', '14052', '可能会引起设备运行温度过高。', 117, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (422, 'EFFECT_SERVICE', '14053', 'DIAMETER链路断，基于DIAMETER协议栈的CSCF网元与CG计费网关之间消息收发会失败。CG网元因为收不到CSCF网元的计费请求消息，因此不能进行正常计费功能，对此时要进行计费的用户会计费失败,导致商业损失。', 118, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (423, 'EFFECT_SERVICE', '14054', '引起这个端口的网络功能异常，业务中断', 119, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (424, 'EFFECT_SERVICE', '14055', 'DIAMETER协议栈暂时无法正常工作，CG网元不能正常计费，导致部分业务中断。\nB200网元发送计费ACR请求消息，到达DIAMETER协议栈后，协议栈此时的会话资源已耗尽（达到100%），无法接受和处理新的消息，消息会被丢掉，ACR不能正常发送到CG网元；CG网元因为收不到B200网元的计费请求消息，因此不能进行正常计费功能，对此时要进行计费的用户会计费失败,导致商业损失。', 120, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (425, 'EFFECT_SERVICE', '14056', '在ia口链路down时，所有的ia口消息都不能正常的发送到对端设备。', 121, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
