INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (440, 'EFFECT_SERVICE', '14071', '积压ACR文件占用的硬盘空间达到了配置的最大可用空间，离线计费失败，导致商业损失。', 136, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (441, 'EFFECT_SERVICE', '14072', '不能及时将ACR话单发给CG，当ACR不断被写入文件，文件占用的硬盘空间达到一定限制后，之后产生的离线计费话单会丢弃，从而导致计费失败，无法进行离线计费，导致商业损失。', 137, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (442, 'EFFECT_SERVICE', '14073', '离线计费数据区占用率过高。如果话单池占用率达到阈值时呼叫处理模式配置为“拒绝”，可能会造成呼叫被释放。', 138, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (443, 'EFFECT_SERVICE', '14074', '如果边界网关所承载的呼叫/注册数量进一步上升，超过系统License配置中针对最大并发在线呼叫许可容量部分的会话建立请求将被拒绝，产生呼损降低系统接通率；随着并发呼叫数量的下降，将恢复正常。', 139, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (444, 'EFFECT_SERVICE', '14075', '当通配号码资源耗尽后，后续通配用户注册失败。', 140, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (445, 'EFFECT_SERVICE', '14076', '新注册用户由于CPU过载被阻塞\n·部分已注册成功低优先级的白名单用户，被阻塞，无法发起呼叫\n·CPU冲高，系统存在超负荷工作的风险，影响部分已注册用户的正常呼叫', 141, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (446, 'EFFECT_SERVICE', '14077', '1、进入循环处理，有自恢复情况，如果是业务任务或者协议栈进入循环处理，可能导致业务的延迟或者断续\n如果时间超过1分钟，会导致系统复位。\n2、如果是信令媒体合一设备，复位期间所有新发起业务请求都会失败，所有当前正在进行的业务会中断。\n3、如果是单纯信令面设备复位，已经开始的数据不会中断，新发起业务失败。\n4、如果是媒体设备复位，当前所有数据业务会中断，新注册业务正常，新呼叫等数据业务会失败。\n5、如果系统做了备份冗余，设备复位会导致业务转移到备份设备进行，业务不受影响。', 142, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (447, 'EFFECT_SERVICE', '14078', '配置的DNS服务器不能为SBC服务，系统配置中使用到该DNS域名的业务，都会受到影响；如果配置的存在备用DNS服务器，且该DNS没有创建socket失败告警，对系统的影响相对会小些', 143, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (448, 'EFFECT_SERVICE', '14079', '试用License超期后边界网关上配置的试用License所承载的注册、呼叫将会中断，超期之前业务不会受到影响', 144, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
INSERT INTO `kafka_field_dict` (`id`, `kafka_field`, `dict_key`, `dict_value`, `sort_order`, `is_enabled`, `remark`, `created_at`, `updated_at`) VALUES (449, 'EFFECT_SERVICE', '14080', '可能会引起设备网管操作失败，影响网管对网元的正常的管理，如果为其它网管误配置或者受到网络工具的端口扫描攻击，还会降低设备的性能，使正常运行的业务受到影响降低效率和质量。', 145, 1, '', '2026-05-25 15:48:06', '2026-05-25 15:48:06');
